// Filter posts scheduled for today with Status='Ready'
const items = $input.all();
const today = new Date();
const todayStr = today.toISOString().split('T')[0]; // YYYY-MM-DD

// Also match common date formats
const todayFormatted = today.toLocaleDateString('en-GB'); // DD/MM/YYYY
const todayUS = today.toLocaleDateString('en-US'); // M/D/YYYY

const todayPosts = items.filter((item, index) => {
  const date = (item.json.Date || '').trim();
  const status = (item.json.Status || '').trim().toLowerCase();

  const isToday = date === todayStr || 
                  date === todayFormatted || 
                  date === todayUS ||
                  date === today.toLocaleDateString('de-DE'); // DD.MM.YYYY

  return isToday && status === 'ready';
}).map((item, index) => ({
  json: {
    ...item.json,
    _rowIndex: index + 2 // For sheet update (1-indexed, +1 for header)
  }
}));

console.log(`Found ${todayPosts.length} posts ready for today (${todayStr})`);
return todayPosts;

// Build Buffer API payload for each post
// Supports: instagram, linkedin, twitter, tiktok
const item = $input.first().json;

const platformMap = {
  'instagram': 'instagram',
  'ig': 'instagram',
  'linkedin': 'linkedin',
  'twitter': 'twitter',
  'x': 'twitter',
  'tiktok': 'tiktok'
};

const platform = platformMap[(item.Platform || '').toLowerCase().trim()] || 'instagram';

// Build media array if image URL provided
const media = item.Image_URL && item.Image_URL.trim() ? 
  [{ url: item.Image_URL.trim(), thumbnail: item.Image_URL.trim() }] : [];

const bufferPayload = {
  profile_ids: [`REPLACE_WITH_BUFFER_PROFILE_ID_${platform.toUpperCase()}`],
  text: item.Caption || '',
  now: true, // Post immediately
  media: media.length > 0 ? { photo: item.Image_URL.trim() } : undefined,
  _originalData: item // Keep for sheet update
};

return [{ json: bufferPayload }];

// Count how many posts were successfully published today
const items = $input.all();
const count = items.length;
const platforms = [...new Set(items.map(i => i.json._originalData?.Platform || 'Unknown'))];

return [{
  json: {
    published_count: count,
    platforms: platforms.join(', '),
    summary: count > 0
      ? `✅ ${count} post${count !== 1 ? 's' : ''} published today on: ${platforms.join(', ')}`
      : '📭 No posts were scheduled for today.',
    date: new Date().toLocaleDateString('en-GB', { weekday: 'long', year: 'numeric', month: 'long', day: 'numeric' })
  }
}];

const error = $input.first().json;
console.error('ME-07 Error:', JSON.stringify(error));
return [{ json: { error: true, message: error.message || 'Posting failed', timestamp: new Date().toISOString() } }];
